INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'lubbock'), 'RE', 're', 'Residential Estates', 'This district provides for very low-density residential neighborhoods with on-site utilities, preserving a rural low-density character and allowing for large animals. It also accommodates residential neighborhoods with a high percentage of common open space.', 45, NULL, 87120, 35, 60, 30, 20, 'Refer to UDC Table 39.02.004.a-3 (RE Off-Street Parking and Loading Schedule) and Division 3.3 (Parking, Loading, Stacking, and Access).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 're' AND z.city_id = (SELECT id FROM cities WHERE slug = 'lubbock') AND pu.name IN ('Single-Family Detached Dwelling', 'Farm, Ranch, or Orchard', 'Community Garden') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'lubbock'), 'SF-1', 'sf-1', 'Very Low Density Single-Family', 'This district is intended for neighborhoods with large to moderately sized lots, each with a single-family detached dwelling and internal street access. It also allows for clustering of moderately sized lots with common open space.', 35, NULL, 21700, 45, 25, 20, 10, 'Refer to UDC Table 39.02.004.b-3 (SF-1 Off-Street Parking and Loading Schedule) and Division 3.3 (Parking, Loading, Stacking, and Access).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
