INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'lubbock'), 'SF-2', 'sf-2', 'Low Density Single-Family', 'This district provides for smaller to moderately-sized lots for single-family detached dwellings on public utilities, with open space located on private lots. It is also the default zoning for annexed lands.', NULL, NULL, 5000, NULL, NULL, NULL, NULL, 'Refer to UDC Table 39.02.004.c-3 (SF-2 Off-Street Parking and Loading Schedule) and Division 3.3 (Parking, Loading, Stacking, and Access).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
