INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'lubbock'), 'LI', 'li', 'Light Industrial', 'This district provides for industrial uses (non-retail) that are less intensive than General Industrial, including office, warehousing, distribution, and light assembly, with operations primarily indoors without creating noxious elements.', NULL, NULL, 20000, NULL, 40, NULL, 100, 'Refer to UDC Table 39.02.006.f-3 (LI Off-Street Parking and Loading Schedule) and Division 3.3 (Parking, Loading, Stacking, and Access).') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
